fn is_file_path_reference(s: &str) -> bool {
        if s.starts_with("http://") || s.starts_with("https://") {
            return false;
        }
        const EXTENSIONS: &[&str] = &[
            ".rs", ".ts", ".tsx", ".js", ".jsx", ".py",
            ".toml", ".yaml", ".yml", ".json", ".md",
        ];
        EXTENSIONS.iter().any(|ext| s.ends_with(ext))
    }
